import {
  Accordion,
  AccordionGroup,
  AccordionHeader,
  AccordionPanel,
  FlowLayout,
  FormField,
  FormFieldLabel,
  Input,
} from "@salt-ds/core";
import { type ReactElement, type SyntheticEvent, useState } from "react";

export const ExclusiveGroup = (): ReactElement => {
  const [expanded, setExpanded] = useState<string>("");

  const onChange = (event: SyntheticEvent<HTMLButtonElement>) => {
    const value = event.currentTarget.value;
    setExpanded((old) => (old === value ? "" : value));
  };

  return (
    <div style={{ width: "80%", height: "100%" }}>
      <AccordionGroup>
        {Array.from({ length: 3 }, (_, i) => i + 1).map((i) => (
          <Accordion
            value={`accordion-${i}`}
            expanded={expanded === `accordion-${i}`}
            onToggle={onChange}
            key={`accordion-${i}`}
          >
            <AccordionHeader>Internal form</AccordionHeader>
            <AccordionPanel>
              <FlowLayout>
                Please fill out the following details.
                <FormField labelPlacement="left">
                  <FormFieldLabel>Disclosure ID</FormFieldLabel>
                  <Input />
                </FormField>
                <FormField labelPlacement="left">
                  <FormFieldLabel>Email</FormFieldLabel>
                  <Input />
                </FormField>
                <FormField labelPlacement="left">
                  <FormFieldLabel>Justification</FormFieldLabel>
                  <Input />
                </FormField>
              </FlowLayout>
            </AccordionPanel>
          </Accordion>
        ))}
      </AccordionGroup>
    </div>
  );
};

import {
  Accordion,
  AccordionGroup,
  AccordionHeader,
  AccordionPanel,
  Checkbox,
  CheckboxGroup,
  FormField,
  FormFieldLabel,
  SplitLayout,
  StackLayout,
  Text,
} from "@salt-ds/core";
import { type ChangeEvent, type ReactElement, useState } from "react";

const accounts = [
  { name: "Account 1", number: "8736" },
  { name: "Account 2", number: "2564" },
];

const features = [
  {
    name: "Domestic wires",
    id: "domestic_wires",
    description: "Initiate wire transfers to another bank",
  },
  {
    name: "Account transfers",
    id: "account_transfers",
    description: "Move money within your accounts",
  },
];

export const AdditionalLabels = (): ReactElement => {
  const [state, setState] = useState<Record<string, string[]>>({
    domestic_wires: [],
    account_transfers: [],
  });

  const handleChange = (event: ChangeEvent<HTMLInputElement>) => {
    const value = event.target.value;
    const name = event.target.name;

    setState((prev) => ({
      ...prev,
      [name]: prev[name].includes(value)
        ? prev[name].filter((account) => account !== value)
        : [...prev[name], value],
    }));
  };

  return (
    <div style={{ width: "80%", height: "100%" }}>
      <AccordionGroup>
        {Object.values(features).map(({ name, description, id }) => (
          <Accordion value={id} key={id}>
            <AccordionHeader>
              <StackLayout gap={0.5}>
                <SplitLayout
                  align="baseline"
                  startItem={
                    <Text>
                      <strong>{name}</strong>
                    </Text>
                  }
                  endItem={
                    <Text styleAs="label" color="secondary">
                      {state[id].length} of {accounts.length} accounts
                    </Text>
                  }
                />
                <Text styleAs="label" color="secondary">
                  {description}
                </Text>
              </StackLayout>
            </AccordionHeader>
            <AccordionPanel>
              <FormField>
                <FormFieldLabel>Accounts for this service</FormFieldLabel>
                <CheckboxGroup
                  checkedValues={state[id]}
                  onChange={handleChange}
                  direction="horizontal"
                >
                  {accounts.map(({ name, number }) => (
                    <Checkbox
                      label={`${name} (...${number})`}
                      name={id}
                      value={number}
                      key={number}
                    />
                  ))}
                </CheckboxGroup>
              </FormField>
            </AccordionPanel>
          </Accordion>
        ))}
      </AccordionGroup>
    </div>
  );
};

import {
  Accordion,
  AccordionGroup,
  AccordionHeader,
  AccordionPanel,
  Button,
  FlowLayout,
  FormField,
  FormFieldLabel,
  Input,
  StackLayout,
} from "@salt-ds/core";
import { CollapseAllIcon, ExpandAllIcon } from "@salt-ds/icons";
import { type ReactElement, useState } from "react";

const accordions = Array.from({ length: 3 }, (_, i) => i + 1);

export const ExpandAll = (): ReactElement => {
  const [expanded, setExpanded] = useState<number[]>([]);

  const handleAccordionToggle = (value: number) => {
    setExpanded((prev) =>
      prev.includes(value)
        ? prev.filter((v) => v !== value)
        : prev.concat(value),
    );
  };

  const handleExpandAll = () => {
    setExpanded(accordions);
  };

  const handleCollapseAll = () => {
    setExpanded([]);
  };

  return (
    <StackLayout
      gap={3}
      style={{ height: "100%", paddingInline: "var(--salt-spacing-300)" }}
    >
      <FlowLayout gap={1}>
        <Button onClick={handleExpandAll}>
          <ExpandAllIcon aria-hidden /> Expand All
        </Button>
        <Button onClick={handleCollapseAll}>
          <CollapseAllIcon aria-hidden /> Collapse All
        </Button>
      </FlowLayout>

      <AccordionGroup>
        {accordions.map((i) => (
          <Accordion
            key={`accordion-${i}`}
            value={`accordion-${i}`}
            expanded={expanded.includes(i)}
            onToggle={() => handleAccordionToggle(i)}
            indicatorSide="right"
          >
            <AccordionHeader>Internal form</AccordionHeader>
            <AccordionPanel>
              <FlowLayout>
                Please fill out the following details.
                <FormField labelPlacement="left">
                  <FormFieldLabel>Disclosure ID</FormFieldLabel>
                  <Input />
                </FormField>
                <FormField labelPlacement="left">
                  <FormFieldLabel>Email</FormFieldLabel>
                  <Input />
                </FormField>
                <FormField labelPlacement="left">
                  <FormFieldLabel>Justification</FormFieldLabel>
                  <Input />
                </FormField>
              </FlowLayout>
            </AccordionPanel>
          </Accordion>
        ))}
      </AccordionGroup>
    </StackLayout>
  );
};

