function groupByFirstLetter(data: string[]) {
  return data.reduce(
    (acc, option) => {
      const groupName = option[0];
      if (!acc[groupName]) {
        acc[groupName] = [];
      }
      acc[groupName].push(option);
      return acc;
    },
    {} as Record<string, string[]>,
  );
}

