export const FormattingThousandsSeparator = () => {
  const isInternationalFormat = (inputValue: string): boolean =>
    /^[+-]?(\d{1,3}(,\d{0,3})*|\d*)(\.?\d*)?$/.test(inputValue);
  return (
    <FormField style={{ width: "256px" }}>
      <FormFieldLabel>Thousands separator</FormFieldLabel>
      <NumberInput
        defaultValue={1000000}
        pattern={isInternationalFormat}
        format={(value) => {
          if (!value.length) {
            return value;
          }
          return new Intl.NumberFormat("en-US").format(
            Number.parseFloat(value.replace(/,/g, "")),
          );
        }}
        parse={(value) => {
          if (!value.length) {
            return null;
          }
          return Number.parseFloat(value.replace(/,/g, ""));
        }}
        onNumberChange={(_event, newValue) => {
          console.log(`Number changed to ${newValue}`);
        }}
      />
    </FormField>
  );
};

import { FormField, FormFieldLabel, NumberInput } from "@salt-ds/core";
import { useState } from "react";

export const FormattingCompactNotation = () => {
  const [value, setValue] = useState<string>("100000");
  const validValue = /^([+-]?\d+(?:\.\d*)?|\.[0-9]+)([kmbt]?)$/i;

  return (
    <FormField style={{ width: "256px" }}>
      <FormFieldLabel>Compact notation</FormFieldLabel>
      <NumberInput
        value={value}
        pattern={(inputValue) => validValue.test(inputValue)}
        onChange={(_event, newValue) => {
          setValue(newValue);
        }}
        onNumberChange={(_event, newValue) => {
          console.log(`Number changed to ${newValue}`);
        }}
        format={(value) => {
          if (!value.length) {
            return value;
          }
          const floatValue = Number.parseFloat(value);
          if (Number.isNaN(floatValue)) {
            return value;
          }
          return new Intl.NumberFormat("en-US", {
            notation: "compact",
            compactDisplay: "short",
            maximumFractionDigits: 3,
          }).format(floatValue);
        }}
        step={1000}
        parse={(raw) => {
          if (!raw.length) {
            return null;
          }
          const match = raw.match(validValue);
          if (!match) {
            return Number.NaN;
          }
          const [_, num, unit] = match;
          const multiplier = unit
            ? { k: 1e3, m: 1e6, b: 1e9, t: 1e12 }[unit.toLowerCase()] || 1
            : 1;
          return Number.parseFloat(num) * multiplier;
        }}
      />
    </FormField>
  );
};

import {
  FormField,
  FormFieldLabel,
  NumberInput,
  StackLayout,
} from "@salt-ds/core";

export const FormattingSuffixPrefix = () => {
  return (
    <StackLayout style={{ width: "256px" }}>
      <FormField>
        <FormFieldLabel>With suffix</FormFieldLabel>
        <NumberInput
          defaultValue={12}
          pattern={(inputValue) =>
            inputValue === "" ||
            inputValue === "-" ||
            inputValue === "+" ||
            /^[+-]?(\d+(\.\d*)?|\.\d+)%?$/.test(inputValue)
          }
          format={(value) => `${value}%`}
          parse={(value) => {
            if (!value.length) {
              return null;
            }
            return Number.parseFloat(value.replace(/%/g, ""));
          }}
          onNumberChange={(_event, newValue) => {
            console.log(`Number changed to ${newValue}`);
          }}
        />
      </FormField>
      <FormField>
        <FormFieldLabel>With prefix</FormFieldLabel>
        <NumberInput
          defaultValue={12}
          pattern={(inputValue) =>
            inputValue === "" ||
            inputValue === "-" ||
            inputValue === "+" ||
            /^\$?[+-]?(\d+(\.\d*)?|\.\d+)?%?$/.test(inputValue)
          }
          format={(value) => `$${value.replace(/\$/g, "")}`}
          parse={(value) => {
            if (!value.length) {
              return null;
            }
            if (value === "$") {
              return 0;
            }
            const parsedValue = value.replace(/\$/g, "");
            return Number.parseFloat(parsedValue);
          }}
          onNumberChange={(_event, newValue) => {
            console.log(`Number changed to ${newValue}`);
          }}
        />
      </FormField>
    </StackLayout>
  );
};

