    <FormFieldLabel>Multiplier</FormFieldLabel>
    <NumberInput
      defaultValue={0}
      pattern={(inputValue) => /^[+-]?\d*x?$/.test(inputValue)}
      format={(value) => `${value}x`}
      parse={(value) => {
        if (!value.length) {
