export const PreferencesDialog = () => {
  const items = [
    {
      label: "Display",
      icon: <LaptopIcon />,
      title: "Display settings",
      view: displayView,
    },
    {
      label: "Account",
      icon: <UserIcon />,
      title: "Account settings",
      view: accountView,
    },
    {
      label: "Export",
      icon: <ExportIcon />,
      title: "Export settings",
      view: exportView,
    },
  ];

  const [visibleView, setVisibleView] = useState<"child" | "parent">("child");

  const showParent = () => {
    setVisibleView("parent");
  };
  const showChild = () => {
    setVisibleView("child");
  };

  const [active, setActive] = useState(items[0]);
  const [collapsed, setCollapsed] = useState<boolean>();
  const [open, setOpen] = useState<boolean>(false);

  const parent = (
    <nav className={styles.parentView}>
      <ul className={styles.navList}>
        {items.map((item) => (
          <li key={item.label}>
            <NavigationItem
              active={active.label === item.label}
              href="#"
              orientation="vertical"
              onClick={(event) => {
                // Prevent default to avoid navigation
                event.preventDefault();
                setActive(item);
                showChild();
              }}
            >
              {item.icon} {item.label}
            </NavigationItem>
          </li>
        ))}
      </ul>
    </nav>
  );

  const child = (
    <FlexLayout direction="column" className={styles.childView}>
      <FlexLayout gap={1}>
        {visibleView === "child" && collapsed && (
          <Button
            onClick={showParent}
            appearance="transparent"
            aria-label="Back"
          >
            <ChevronLeftIcon />
          </Button>
        )}
        <H2>{active.label}</H2>
      </FlexLayout>
      {active.view?.()}
    </FlexLayout>
  );

  const handleCollapsed = (isCollapsed: boolean) => {
    setCollapsed(isCollapsed);
  };

  const handleRequestOpen = () => {
    setOpen(true);
  };

  const onOpenChange = (value: boolean) => {
    setOpen(value);
  };

  const handleClose = () => {
    setOpen(false);
  };

  return (
    <>
      <Button onClick={handleRequestOpen}>Open Preferences Dialog</Button>
      <Dialog
        size={"medium"}
        open={open}
        onOpenChange={onOpenChange}
        className={styles.dialog}
      >
        <DialogCloseButton onClick={handleClose} />
        <DialogContent>
          <ParentChildLayout
            gap={1}
            visibleView={visibleView}
            parent={parent}
            child={child}
            onCollapseChange={handleCollapsed}
            className={styles.container}
          />
        </DialogContent>
      </Dialog>
    </>
  );
};

